mapper.select:
SELECT po.id, po.po_id, po.supplier_id, po.order_date, po.status, po.item, s.supplier_name, co.customer_name, (SELECT SUM(poi.quantity) FROM purchase_order_items poi WHERE poi.po_id = po.po_id) AS total_quantity FROM purchase_orders po LEFT JOIN suppliers s ON po.supplier_id = s.supplier_id LEFT JOIN customer_orders co ON po.po_id LIKE CONCAT('%', co.order_no)
(s.supplier_name LIKE CONCAT('%', #{q}, '%') OR po.po_id LIKE CONCAT('%', #{q}, '%') OR po.status LIKE CONCAT('%', #{q}, '%'))
ORDER BY po.order_date DESC LIMIT #{size} OFFSET #{offset}
